import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import { addSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function AddSale() {
  const navigate = useNavigate();
  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [vehicles, setVehicles] = useState([]);
  const [leads, setLeads] = useState([]);

  const [form, setForm] = useState({
    vehicle: "",
    customer: "",
    price: "",
    payment_status: "pending",
  });

  const [error, setError] = useState("");

  useEffect(() => {
    if (!canManage) {
      alert("Access denied");
      navigate("/vehicles");
      return;
    }

    const load = async () => {
      setError("");
      setLoading(true);
      try {
        const [vRes, lRes] = await Promise.all([api.get("/vehicles"), api.get("/leads")]);

        const availableVehicles = (vRes.data || []).filter((v) => v.status === "available");
        const leadList = lRes.data || [];

        setVehicles(availableVehicles);
        setLeads(leadList);

        setForm((prev) => ({
          ...prev,
          vehicle: availableVehicles[0]?._id || "",
          customer: leadList[0]?._id || "",
        }));
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load vehicles/leads");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [canManage, navigate]);

  const selectedVehicle = useMemo(
    () => vehicles.find((v) => v._id === form.vehicle),
    [vehicles, form.vehicle]
  );

  const selectedLead = useMemo(
    () => leads.find((l) => l._id === form.customer),
    [leads, form.customer]
  );

  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    setError("");

    if (!form.vehicle) return setError("Please select a vehicle");
    if (!form.customer) return setError("Please select a customer (lead)");
    if (form.price === "" || Number(form.price) < 0) return setError("Price must be 0 or more");

    setSaving(true);
    try {
      await addSale({
        vehicle: form.vehicle,
        customer: form.customer,
        price: Number(form.price),
        payment_status: form.payment_status,
      });

      alert("Sale saved successfully!");
      navigate("/sales");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to save sale");
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div style={{ padding: 20, display: "flex", justifyContent: "center" }}>
      <div style={{ width: "100%", maxWidth: 720 }}>
        <div
          style={{
            border: "1px solid #e5e7eb",
            borderRadius: 14,
            padding: 16,
            background: "#fff",
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <h2 style={{ margin: 0 }}>Add Sale</h2>
            <button onClick={() => navigate("/sales")} style={btnGhost}>
              Back
            </button>
          </div>

          <p style={{ marginTop: 6, opacity: 0.75 }}>
            Create a sale record (Admin/Manager only). If payment is <b>completed</b>, vehicle will be marked as <b>sold</b>.
          </p>

          {error && (
            <div style={errorBox}>
              <b>Error:</b> {error}
            </div>
          )}

          <form onSubmit={submit} style={{ marginTop: 12 }}>
            {/* Vehicle */}
            <div style={fieldRow}>
              <label style={label}>Vehicle</label>
              <select
                name="vehicle"
                value={form.vehicle}
                onChange={onChange}
                required
                style={input}
                disabled={vehicles.length === 0}
              >
                {vehicles.length === 0 ? (
                  <option value="">No available vehicles</option>
                ) : (
                  vehicles.map((v) => (
                    <option key={v._id} value={v._id}>
                      {v.brand} {v.model || v.type || ""} ({v.year}) — {v.status}
                    </option>
                  ))
                )}
              </select>
              {selectedVehicle && (
                <div style={hint}>
                  Selected: <b>{selectedVehicle.brand}</b> {selectedVehicle.model || selectedVehicle.type || ""} — Rs.{" "}
                  {Number(selectedVehicle.price || 0).toLocaleString()}
                </div>
              )}
            </div>

            {/* Customer */}
            <div style={fieldRow}>
              <label style={label}>Customer (Lead)</label>
              <select
                name="customer"
                value={form.customer}
                onChange={onChange}
                required
                style={input}
                disabled={leads.length === 0}
              >
                {leads.length === 0 ? (
                  <option value="">No leads</option>
                ) : (
                  leads.map((l) => (
                    <option key={l._id} value={l._id}>
                      {l.name} — {l.contact_number || "-"}
                    </option>
                  ))
                )}
              </select>
              {selectedLead && (
                <div style={hint}>
                  Selected: <b>{selectedLead.name}</b> {selectedLead.email ? `(${selectedLead.email})` : ""}
                </div>
              )}
            </div>

            {/* Price + Payment */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <div style={fieldRow}>
                <label style={label}>Price (Rs.)</label>
                <input
                  name="price"
                  type="number"
                  min="0"
                  value={form.price}
                  onChange={onChange}
                  required
                  style={input}
                  placeholder="e.g. 5500000"
                />
              </div>

              <div style={fieldRow}>
                <label style={label}>Payment Status</label>
                <select
                  name="payment_status"
                  value={form.payment_status}
                  onChange={onChange}
                  style={input}
                >
                  <option value="pending">Pending</option>
                  <option value="partial">Partial</option>
                  <option value="completed">Completed</option>
                </select>
              </div>
            </div>

            <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
              <button type="submit" style={btnPrimary} disabled={saving || vehicles.length === 0}>
                {saving ? "Saving..." : "Save Sale"}
              </button>
              <button type="button" style={btnGhost} onClick={() => navigate("/sales")} disabled={saving}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

const fieldRow = { marginTop: 12 };
const label = { display: "block", marginBottom: 6, fontWeight: 600 };
const input = {
  width: "100%",
  padding: "10px 12px",
  borderRadius: 10,
  border: "1px solid #d1d5db",
  outline: "none",
};
const hint = { marginTop: 6, fontSize: 12, opacity: 0.75 };
const errorBox = {
  marginTop: 12,
  padding: 10,
  borderRadius: 10,
  border: "1px solid #fca5a5",
  background: "#fff1f2",
};
const btnPrimary = {
  padding: "10px 14px",
  borderRadius: 10,
  border: "1px solid #111827",
  background: "#111827",
  color: "#fff",
  cursor: "pointer",
};
const btnGhost = {
  padding: "10px 14px",
  borderRadius: 10,
  border: "1px solid #d1d5db",
  background: "#fff",
  cursor: "pointer",
};
